+        let decision = FallbackDecision::from_error("test error");
+        assert_eq!(decision.level, FallbackLevel::Failed);
+        assert!(decision.is_degraded());
+        assert!(matches!(decision.reason, FallbackReason::AnalysisError(_)));
+    }
+
