+    fn fallback_policy_graceful_allows_degradation() {
+        let decision = FallbackDecision::from_error("test");
+        let result = apply_fallback_policy(FallbackMode::Graceful, &decision);
+        assert!(result.is_ok());
+    }
+
+    #[test]
