+        let decision = FallbackDecision::from_error("test");
+        let result = apply_fallback_policy(FallbackMode::Strict, &decision);
+        assert!(result.is_err());
+        let err = result.unwrap_err();
+        assert!(err.message.contains("Strict mode"));
+    }
+
